1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteOptions {
13	  followUp?: boolean;
14	}
15	
16	export interface QuoteResult {
17	  basePremium: number;
18	  premium: number;
19	}
20	
21	const basePremiumByType: Record<string, number> = {
22	  amulet: 60,
23	  sword: 100,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	};
28	
29	const PROCESSING_FEE = 5;
30	const THREE_RUNE_BLOCK_PREMIUM = 60;
31	
32	export function quote(
33	  _customer: Customer,
34	  items: Item[],
35	  _options: QuoteOptions = {},
36	): QuoteResult {
37	  const sumOfBasePremiums = items.reduce(
38	    (sum, item) => sum + basePremiumByType[item.type],
39	    0,
40	  );
41	  const isThreeAlikeRuneBlock =
42	    items.length === 3 && items.every((item) => item.type === "rune");
43	  const basePremium = isThreeAlikeRuneBlock
44	    ? THREE_RUNE_BLOCK_PREMIUM
45	    : sumOfBasePremiums;
46	  const premium = items.length === 0 ? PROCESSING_FEE : 0;
47	  return { basePremium, premium };
48	}
49	
50	export function claim(): unknown {
51	  return undefined;
52	}
